const cityAliases = {
  '–į–Ľ–ľ–į—ā—č': '–ź–Ľ–ľ–į—ā—č',
  '–į—Ā—ā–į–Ĺ–į': '–ź—Ā—ā–į–Ĺ–į',
  '–Ĺ—É—Ä-—Ā—É–Ľ—ā–į–Ĺ': '–ź—Ā—ā–į–Ĺ–į',
  '–Ĺ—É—Ä—Ā—É–Ľ—ā–į–Ĺ': '–ź—Ā—ā–į–Ĺ–į',
  '—ą—č–ľ–ļ–Ķ–Ĺ—ā': '–®—č–ľ–ļ–Ķ–Ĺ—ā',
  '–ļ–į—Ä–į–≥–į–Ĺ–ī–į': '–ö–į—Ä–į–≥–į–Ĺ–ī–į',
  '–į–ļ—ā–į—É': '–ź–ļ—ā–į—É',
  '–į—ā—č—Ä–į—É': '–ź—ā—č—Ä–į—É',
  '–Ņ–į–≤–Ľ–ĺ–ī–į—Ä': '–ü–į–≤–Ľ–ĺ–ī–į—Ä',
  '–ļ–ĺ—Ā—ā–į–Ĺ–į–Ļ': '–ö–ĺ—Ā—ā–į–Ĺ–į–Ļ',
  '—É—Ā—ā—Ć-–ļ–į–ľ–Ķ–Ĺ–ĺ–≥–ĺ—Ä—Ā–ļ': '–£—Ā—ā—Ć-–ö–į–ľ–Ķ–Ĺ–ĺ–≥–ĺ—Ä—Ā–ļ',
};

const knownActivities = [
  '–°—ā—Ä–ĺ–ł—ā–Ķ–Ľ—Ć—Ā—ā–≤–ĺ –∑–ī–į–Ĺ–ł–Ļ –ł —Ā–ĺ–ĺ—Ä—É–∂–Ķ–Ĺ–ł–Ļ',
  '–ö–ĺ–Ĺ—Ā–į–Ľ—ā–ł–Ĺ–≥–ĺ–≤—č–Ķ —É—Ā–Ľ—É–≥–ł',
  '–ě–Ī—Ä–į–∑–ĺ–≤–į—ā–Ķ–Ľ—Ć–Ĺ—č–Ķ —É—Ā–Ľ—É–≥–ł',
  '–Ę–Ķ–Ľ–Ķ–ļ–ĺ–ľ–ľ—É–Ĺ–ł–ļ–į—Ü–ł–ł',
  '–†–ĺ–∑–Ĺ–ł—á–Ĺ–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź',
  '–Ę–Ķ—Ö–Ĺ–ł—á–Ķ—Ā–ļ–ĺ–Ķ –ĺ–Ī—Ā–Ľ—É–∂–ł–≤–į–Ĺ–ł–Ķ –ĺ–Ī–ĺ—Ä—É–ī–ĺ–≤–į–Ĺ–ł—Ź',
  '–ü—Ä–ĺ–ł–∑–≤–ĺ–ī—Ā—ā–≤–ĺ –Ņ—Ä–ĺ–ī—É–ļ—ā–ĺ–≤ –Ņ–ł—ā–į–Ĺ–ł—Ź',
  '–°–Ķ–Ľ—Ć—Ā–ļ–ĺ–Ķ —Ö–ĺ–∑—Ź–Ļ—Ā—ā–≤–ĺ',
  '–Ē–ĺ–Ī—č—á–į –Ņ–ĺ–Ľ–Ķ–∑–Ĺ—č—Ö –ł—Ā–ļ–ĺ–Ņ–į–Ķ–ľ—č—Ö',
  '–Ę—Ä–į–Ĺ—Ā–Ņ–ĺ—Ä—ā –ł –Ľ–ĺ–≥–ł—Ā—ā–ł–ļ–į',
  '–ú–Ķ–ī–ł—Ü–ł–Ĺ—Ā–ļ–ł–Ķ —É—Ā–Ľ—É–≥–ł',
  '–ź—Ä—Ö–ł—ā–Ķ–ļ—ā—É—Ä–į –ł –Ņ—Ä–ĺ–Ķ–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ–ł–Ķ',
  '–ě–Ņ—ā–ĺ–≤–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź',
  '–†–Ķ–ļ–Ľ–į–ľ–Ĺ—č–Ķ —É—Ā–Ľ—É–≥–ł',
  '–†–į–∑—Ä–į–Ī–ĺ—ā–ļ–į –Ņ—Ä–ĺ–≥—Ä–į–ľ–ľ–Ĺ–ĺ–≥–ĺ –ĺ–Ī–Ķ—Ā–Ņ–Ķ—á–Ķ–Ĺ–ł—Ź',
  '–ģ—Ä–ł–ī–ł—á–Ķ—Ā–ļ–ł–Ķ —É—Ā–Ľ—É–≥–ł',
  '–ü—Ä–ĺ–ł–∑–≤–ĺ–ī—Ā—ā–≤–ĺ –ľ–Ķ–Ī–Ķ–Ľ–ł',
  '–§–ł–Ĺ–į–Ĺ—Ā–ĺ–≤—č–Ķ —É—Ā–Ľ—É–≥–ł',
  '–Ď—É—Ö–≥–į–Ľ—ā–Ķ—Ä—Ā–ļ–ł–Ļ —É—á—Ď—ā –ł –į—É–ī–ł—ā',
  '–†–Ķ—Ā—ā–ĺ—Ä–į–Ĺ–Ĺ—č–Ļ –Ī–ł–∑–Ĺ–Ķ—Ā',
];

function compactText(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeForMatch(s) {
  return compactText(s)
    .toLowerCase()
    .replace(/["¬ę¬Ľ']/g, '')
    .replace(/(^|[\s\-])(—ā–ĺ–ĺ|–į–ĺ|–ł–Ņ)(?=$|[\s\-])/giu, ' ')
    .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function detectCity(lower) {
  const cityRules = [
    { canon: '–ź—Ā—ā–į–Ĺ–į', regex: /(–Ĺ—É—Ä-?—Ā—É–Ľ—ā–į–Ĺ|–į—Ā—ā–į–Ĺ)/i },
    { canon: '–ź–Ľ–ľ–į—ā—č', regex: /(–į–Ľ–ľ–į—ā)/i },
    { canon: '–®—č–ľ–ļ–Ķ–Ĺ—ā', regex: /(—ą—č–ľ–ļ–Ķ–Ĺ—ā)/i },
    { canon: '–ö–į—Ä–į–≥–į–Ĺ–ī–į', regex: /(–ļ–į—Ä–į–≥–į–Ĺ–ī)/i },
    { canon: '–ź–ļ—ā–į—É', regex: /(–į–ļ—ā–į—É)/i },
    { canon: '–ź—ā—č—Ä–į—É', regex: /(–į—ā—č—Ä–į—É)/i },
    { canon: '–ü–į–≤–Ľ–ĺ–ī–į—Ä', regex: /(–Ņ–į–≤–Ľ–ĺ–ī–į—Ä)/i },
    { canon: '–ö–ĺ—Ā—ā–į–Ĺ–į–Ļ', regex: /(–ļ–ĺ—Ā—ā–į–Ĺ–į–Ļ)/i },
    { canon: '–£—Ā—ā—Ć-–ö–į–ľ–Ķ–Ĺ–ĺ–≥–ĺ—Ä—Ā–ļ', regex: /(—É—Ā—ā—Ć-?–ļ–į–ľ–Ķ–Ĺ–ĺ–≥–ĺ—Ä—Ā–ļ)/i },
  ];

  for (const rule of cityRules) {
    if (rule.regex.test(lower)) return rule.canon;
  }

  for (const [alias, canon] of Object.entries(cityAliases)) {
    if (lower.includes(alias)) return canon;
  }

  return null;
}

function detectActivity(lower) {
  for (const v of knownActivities) {
    if (lower.includes(v.toLowerCase())) return v;
  }

  if (/(—Ä–į–∑—Ä–į–Ī–ĺ—ā–ļ|–Ņ—Ä–ĺ–≥—Ä–į–ľ–ľ|it|–į–Ļ—ā–ł|software|—ā–Ķ—Ö–Ĺ–ĺ–Ľ–ĺ–≥)/i.test(lower)) return '–†–į–∑—Ä–į–Ī–ĺ—ā–ļ–į –Ņ—Ä–ĺ–≥—Ä–į–ľ–ľ–Ĺ–ĺ–≥–ĺ –ĺ–Ī–Ķ—Ā–Ņ–Ķ—á–Ķ–Ĺ–ł—Ź';
  if (/(—Ā—ā—Ä–ĺ–ł—ā|construction|–∑–ī–į–Ĺ–ł–Ļ|—Ā–ĺ–ĺ—Ä—É–∂–Ķ–Ĺ–ł–Ļ)/i.test(lower)) return '–°—ā—Ä–ĺ–ł—ā–Ķ–Ľ—Ć—Ā—ā–≤–ĺ –∑–ī–į–Ĺ–ł–Ļ –ł —Ā–ĺ–ĺ—Ä—É–∂–Ķ–Ĺ–ł–Ļ';
  if (/(—ā–Ķ—Ö–Ĺ–ł—á|–ĺ–Ī—Ā–Ľ—É–∂–ł–≤–į–Ĺ.*–ĺ–Ī–ĺ—Ä—É–ī)/i.test(lower)) return '–Ę–Ķ—Ö–Ĺ–ł—á–Ķ—Ā–ļ–ĺ–Ķ –ĺ–Ī—Ā–Ľ—É–∂–ł–≤–į–Ĺ–ł–Ķ –ĺ–Ī–ĺ—Ä—É–ī–ĺ–≤–į–Ĺ–ł—Ź';
  if (/(–į—Ä—Ö–ł—ā–Ķ–ļ—ā|–Ņ—Ä–ĺ–Ķ–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ)/i.test(lower)) return '–ź—Ä—Ö–ł—ā–Ķ–ļ—ā—É—Ä–į –ł –Ņ—Ä–ĺ–Ķ–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ–ł–Ķ';
  if (/(—ā—Ä–į–Ĺ—Ā–Ņ–ĺ—Ä—ā|–Ľ–ĺ–≥–ł—Ā—ā|–ī–ĺ—Ā—ā–į–≤–ļ|—Ā–ļ–Ľ–į–ī)/i.test(lower)) return '–Ę—Ä–į–Ĺ—Ā–Ņ–ĺ—Ä—ā –ł –Ľ–ĺ–≥–ł—Ā—ā–ł–ļ–į';
  if (/(–ĺ–Ņ—ā–ĺ–≤)/i.test(lower)) return '–ě–Ņ—ā–ĺ–≤–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź';
  if (/(—Ä–ĺ–∑–Ĺ–ł—á)/i.test(lower)) return '–†–ĺ–∑–Ĺ–ł—á–Ĺ–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź';
  if (/(—Ą–ł–Ĺ–į–Ĺ—Ā|–Ī–į–Ĺ–ļ|–ł–Ĺ–≤–Ķ—Ā—ā|—Ā—ā—Ä–į—Ö)/i.test(lower)) return '–§–ł–Ĺ–į–Ĺ—Ā–ĺ–≤—č–Ķ —É—Ā–Ľ—É–≥–ł';

  return null;
}

function normalizeLegalFormPrefix(s) {
  return compactText(s)
    .replace(/^—ā–ĺ–ĺ\b/i, '–Ę–ě–ě')
    .replace(/^–į–ĺ\b/i, '–ź–ě')
    .replace(/^–ł–Ņ\b/i, '–ė–ü');
}

function cleanupFreeformCompanyHint(raw, city) {
  let hint = normalizeForMatch(raw);
  if (!hint) return '';

  const cityNorm = normalizeForMatch(city || '');
  if (cityNorm) {
    const cityTokens = new Set(cityNorm.split(' ').filter(Boolean));
    hint = hint
      .split(' ')
      .filter((t) => t && !cityTokens.has(t))
      .join(' ');
  }

  hint = hint
    .replace(/\b(–ļ–į–ļ–ĺ–Ļ|–ļ–į–ļ–į—Ź|–ļ–į–ļ–ł–Ķ|–ļ–į–ļ—É—é|–≥–ī–Ķ|–ļ–ĺ–≥–ī–į|—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ|–ļ–ĺ–Ľ–ł—á–Ķ—Ā—ā–≤–ĺ|—á–ł—Ā–Ľ–ĺ|—Ā—ā–į—ā—É—Ā|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—Ź|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł–ł|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—é|–ī–į—ā–į|—Ä–Ķ–≥–ł—Ā—ā—Ä–į—Ü–ł–ł|–≤–ł–ī|–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā–ł|—á–Ķ–ľ|–∑–į–Ĺ–ł–ľ–į–Ķ—ā—Ā—Ź|–∑–į–Ĺ–ł–ľ–į—é—ā—Ā—Ź|–Ĺ–į–Ļ–ī–ł|–Ņ–ĺ–ļ–į–∂–ł|–Ņ–Ķ—Ä–Ķ—á–ł—Ā–Ľ–ł|—Ā–Ņ–ł—Ā–ĺ–ļ|–≤—Ā–Ķ|–Ņ–ĺ–ī–Ī–Ķ—Ä–ł|–Ņ–ĺ|–≤|—É|–Ĺ–į|–ł–∑)\b/giu, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return hint;
}

function detectLegalForm(chatInput) {
  const m = chatInput.match(/(?:^|[\s"¬ę¬Ľ'().,!?;:])(—ā–ĺ–ĺ|–į–ĺ|–ł–Ņ)(?=$|[\s"¬ę¬Ľ'().,!?;:])/iu);
  if (!m || !m[1]) return null;
  const v = m[1].toUpperCase();
  if (v === '–Ę–ě–ě' || v === '–ź–ě' || v === '–ė–ü') return v;
  return null;
}

function detectCompanyName(chatInput, lower, city) {
  const quotedLegal = chatInput.match(/(?:–Ę–ě–ě|–ź–ě|–ė–ü)\s*["¬ę][^"¬Ľ]+["¬Ľ]/i);
  if (quotedLegal && quotedLegal[0]) {
    const exact = normalizeLegalFormPrefix(quotedLegal[0].replace(/[¬ę¬Ľ]/g, '"'));
    const hint = normalizeForMatch(exact);
    return { exact, hint, confidence: 'high' };
  }

  const quotedAny = chatInput.match(/["¬ę]([^"¬Ľ]{2,})["¬Ľ]/);
  if (quotedAny && quotedAny[1]) {
    const exact = compactText(quotedAny[1]);
    const hint = normalizeForMatch(exact);
    return { exact: null, hint, confidence: 'medium' };
  }

  const phrase = chatInput.match(/(?:–ļ–ĺ–ľ–Ņ–į–Ĺ–ł[–ł—Ź–ł]\s+|—É\s+–ļ–ĺ–ľ–Ņ–į–Ĺ–ł[–ł—Ź–ł]\s+)([\p{L}\p{N}\s-]{3,})/iu);
  if (phrase && phrase[1]) {
    const raw = compactText(phrase[1]).replace(/[?!.,;:]+$/g, '');
    const hint = normalizeForMatch(raw);
    if (hint) return { exact: null, hint, confidence: 'low' };
  }

  const statusSubject = chatInput.match(/(?:–ļ–į–ļ–ĺ–Ļ\s+—Ā—ā–į—ā—É—Ā\s+—É|—Ā—ā–į—ā—É—Ā\s+—É)\s+([\p{L}\p{N}\s"¬ę¬Ľ.-]{3,})/iu);
  if (statusSubject && statusSubject[1]) {
    const raw = compactText(statusSubject[1])
      .replace(/[?!.,;:]+$/g, '')
      .replace(/\s+(–≤|–ł–∑|–Ņ–ĺ)\s+[^\s]+.*$/iu, '')
      .trim();
    const hint = normalizeForMatch(raw);
    if (hint && !/^(–ļ–ĺ–ľ–Ņ–į–Ĺ–ł|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—Ź|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—é)$/.test(hint)) {
      return { exact: null, hint, confidence: 'medium' };
    }
  }

  const freeformHint = cleanupFreeformCompanyHint(chatInput, city);
  if (freeformHint && freeformHint.split(' ').length <= 4) {
    return { exact: null, hint: freeformHint, confidence: 'low' };
  }

  return { exact: null, hint: null, confidence: 'none' };
}

function needsSemanticFallback(lower, hasAnyFilter, queryMode) {
  if (queryMode === 'generic') return true;
  if (!hasAnyFilter && queryMode === 'list') return true;
  if (/(–Ņ–ĺ—Ö–ĺ–∂|–į–Ĺ–į–Ľ–ĺ–≥|—Ā—Ö–ĺ–∂|–Ņ—Ä–ł–ľ–Ķ—Ä–Ĺ–ĺ|—ā–Ķ—Ö–Ĺ–ĺ–Ľ–ĺ–≥–ł—á–Ķ—Ā–ļ|—á—ā–ĺ[- ]?—ā–ĺ|–ļ–į–ļ–ł–Ķ\s+–Ķ—Ā—ā—Ć)/i.test(lower)) return true;
  return false;
}

function extractAnswerBranch(rawInput) {
  let text = compactText(rawInput);
  let branch = 'fast';

  const slashMode = text.match(/^\/mode\s+(rag|fast)\b/i);
  if (slashMode) {
    branch = slashMode[1].toLowerCase();
    text = compactText(text.replace(/^\/mode\s+(rag|fast)\b/i, ''));
    return { branch, chatInput: text };
  }

  const slashShort = text.match(/^\/(rag|fast)\b/i);
  if (slashShort) {
    branch = slashShort[1].toLowerCase();
    text = compactText(text.replace(/^\/(rag|fast)\b/i, ''));
    return { branch, chatInput: text };
  }

  const hashTag = text.match(/#(rag|fast)\b/i);
  if (hashTag) {
    branch = hashTag[1].toLowerCase();
    text = compactText(text.replace(/#(rag|fast)\b/i, ''));
  }

  return { branch, chatInput: text };
}

const getGlobalStaticData = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (typeof this !== 'undefined' && this && typeof this.getWorkflowStaticData === 'function') {
    return this.getWorkflowStaticData('global');
  }
  return null;
};

return $input.all().map((item) => {
  const original = item.json || {};
  const branchDecision = extractAnswerBranch(original.chatInput ?? '');
  const answerBranch = branchDecision.branch === 'rag' ? 'rag' : 'fast';
  const chatInput = compactText(branchDecision.chatInput || original.chatInput || '');
  const lower = chatInput.toLowerCase();

  const city = detectCity(lower);
  const activity = detectActivity(lower);
  const company = detectCompanyName(chatInput, lower, city);
  const legalForm = detectLegalForm(chatInput);

  const binMatch = chatInput.match(/\b\d{12}\b/);
  const bin = binMatch ? binMatch[0] : null;

  let status = null;
  if (/(–Ĺ–Ķ–į–ļ—ā–ł–≤|–Ľ–ł–ļ–≤–ł–ī|–∑–į–ļ—Ä—č—ā|–Ņ—Ä–ł–ĺ—Ā—ā–į–Ĺ–ĺ–≤)/i.test(lower)) status = '–õ–ł–ļ–≤–ł–ī–ł—Ä–ĺ–≤–į–Ĺ–ĺ';
  else if (lower.includes('–į–ļ—ā–ł–≤–Ĺ')) status = '–ź–ļ—ā–ł–≤–Ĺ–ĺ';

  const isCount = /(—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ|–ļ–ĺ–Ľ–ł—á–Ķ—Ā—ā–≤–ĺ|—á–ł—Ā–Ľ–ĺ)/i.test(lower);
  const isStatusLookup = /(–ļ–į–ļ–ĺ–Ļ\s+—Ā—ā–į—ā—É—Ā|—Ā—ā–į—ā—É—Ā\s+—É\s+–ļ–ĺ–ľ–Ņ–į–Ĺ–ł)/i.test(lower);
  const isDateLookup = /(–ī–į—ā–į\s+—Ä–Ķ–≥–ł—Ā—ā—Ä–į—Ü|–ļ–ĺ–≥–ī–į\s+–∑–į—Ä–Ķ–≥–ł—Ā—ā—Ä)/i.test(lower);
  const isActivityLookup = /(–≤–ł–ī\s+–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā|—á–Ķ–ľ\s+–∑–į–Ĺ–ł–ľ–į(?:–Ķ—ā—Ā—Ź|—é—ā|–Ķ—ą—Ć—Ā—Ź)|–ļ–į–ļ–į—Ź\s+–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā|–ļ–į–ļ–ĺ–Ļ\s+–≤–ł–ī\s+–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā|—á—ā–ĺ\s+–ī–Ķ–Ľ–į(?:–Ķ—ā|—é—ā)\s+–ļ–ĺ–ľ–Ņ–į–Ĺ–ł)/i.test(lower);
  const isList = /(–Ĺ–į–Ļ–ī–ł|–Ņ–ĺ–ļ–į–∂–ł|–Ņ–Ķ—Ä–Ķ—á–ł—Ā–Ľ–ł|–ļ–į–ļ–ł–Ķ|—Ā–Ņ–ł—Ā–ĺ–ļ|–≤—Ā–Ķ|–Ņ–ĺ–ī–Ī–Ķ—Ä–ł)/i.test(lower);

  const asksUnsupportedField = /(–≤—č—Ä—É—á–ļ|–ī–ĺ—Ö–ĺ–ī|–ĺ–Ī–ĺ—Ä–ĺ—ā|–Ņ—Ä–ł–Ī—č–Ľ|–ľ–į—Ä–∂–ł–Ĺ|ebitda|–ī–ł–≤–ł–ī–Ķ–Ĺ–ī|–ļ–į–Ņ–ł—ā–į–Ľ–ł–∑–į—Ü|–į–ļ—ā–ł–≤—č|–Ī–į–Ľ–į–Ĺ—Ā|—ā–Ķ–Ľ–Ķ—Ą–ĺ–Ĺ|e-?mail|–Ņ–ĺ—á—ā|—Ā–į–Ļ—ā|–į–ī—Ä–Ķ—Ā|—Ä—É–ļ–ĺ–≤–ĺ–ī–ł—ā–Ķ–Ľ|—É—á—Ä–Ķ–ī–ł—ā–Ķ–Ľ|–ī–ł—Ä–Ķ–ļ—ā–ĺ—Ä|–≤–Ľ–į–ī–Ķ–Ľ–Ķ—Ü|—ą—ā–į—ā|—Ā–ĺ—ā—Ä—É–ī–Ĺ–ł–ļ)/i.test(lower);
  const asksRankingWithoutMetric = /(–ļ—Ä—É–Ņ–Ĺ–Ķ–Ļ—ą|—ā–ĺ–Ņ\s*\d+|–Ľ—É—á—ą(–ł–Ļ|–į—Ź|–ł–Ķ)|—Ā–į–ľ(—č–Ļ|–į—Ź|–ĺ–Ķ|—č–Ķ))/i.test(lower);

  let unsupportedReason = null;
  if (asksUnsupportedField) unsupportedReason = '–ó–į–Ņ—Ä–ĺ—ą–Ķ–Ĺ—č –Ņ–ĺ–Ľ—Ź, –ļ–ĺ—ā–ĺ—Ä—č—Ö –Ĺ–Ķ—ā –≤ –ł—Ā—ā–ĺ—á–Ĺ–ł–ļ–Ķ –ī–į–Ĺ–Ĺ—č—Ö.';
  else if (asksRankingWithoutMetric) unsupportedReason = '–ó–į–Ņ—Ä–ĺ—ą–Ķ–Ĺ —Ä–Ķ–Ļ—ā–ł–Ĺ–≥/—Ā—Ä–į–≤–Ĺ–Ķ–Ĺ–ł–Ķ, –Ĺ–ĺ –≤ –ł—Ā—ā–ĺ—á–Ĺ–ł–ļ–Ķ –Ĺ–Ķ—ā –ľ–Ķ—ā—Ä–ł–ļ —Ä–į–Ĺ–∂–ł—Ä–ĺ–≤–į–Ĺ–ł—Ź.';

  let queryMode = 'generic';
  if (unsupportedReason) queryMode = 'unsupported';
  else if (isCount) queryMode = 'count';
  else if (bin) queryMode = 'bin_lookup';
  else if (isStatusLookup) queryMode = 'status_lookup';
  else if (isDateLookup) queryMode = 'registration_date_lookup';
  else if (isActivityLookup) queryMode = 'activity_lookup';
  else if (isList) queryMode = 'list';

  const shortEntityLookup =
    queryMode === 'generic'
    && !unsupportedReason
    && !bin
    && Boolean(company.hint)
    && !/(—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ|–ļ–ĺ–Ľ–ł—á–Ķ—Ā—ā–≤–ĺ|—á–ł—Ā–Ľ–ĺ|–Ĺ–į–Ļ–ī–ł|–Ņ–ĺ–ļ–į–∂–ł|–Ņ–Ķ—Ä–Ķ—á–ł—Ā–Ľ–ł|–ļ–į–ļ–ł–Ķ|—Ā–Ņ–ł—Ā–ĺ–ļ|–≤—Ā–Ķ|–Ņ–ĺ–ī–Ī–Ķ—Ä–ł|–Ņ–ĺ—Ö–ĺ–∂|–į–Ĺ–į–Ľ–ĺ–≥|—Ā—Ö–ĺ–∂|—ā–ĺ–Ņ|–ļ—Ä—É–Ņ–Ĺ–Ķ–Ļ—ą)/i.test(lower)
    && (Boolean(city) || Boolean(legalForm) || company.confidence === 'high' || company.hint.split(' ').length <= 3);

  if (shortEntityLookup) queryMode = 'status_lookup';

