function compact(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeForMatch(s) {
  return compact(s)
    .toLowerCase()
    .replace(/["¬ę¬Ľ']/g, '')
    .replace(/(^|[\s\-])(—ā–ĺ–ĺ|–į–ĺ|–ł–Ņ)(?=$|[\s\-])/giu, ' ')
    .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
    .replace(/\s+/g, ' ')
