  '–†–ĺ–∑–Ĺ–ł—á–Ĺ–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź',
  '–Ę–Ķ—Ö–Ĺ–ł—á–Ķ—Ā–ļ–ĺ–Ķ –ĺ–Ī—Ā–Ľ—É–∂–ł–≤–į–Ĺ–ł–Ķ –ĺ–Ī–ĺ—Ä—É–ī–ĺ–≤–į–Ĺ–ł—Ź',
  '–ü—Ä–ĺ–ł–∑–≤–ĺ–ī—Ā—ā–≤–ĺ –Ņ—Ä–ĺ–ī—É–ļ—ā–ĺ–≤ –Ņ–ł—ā–į–Ĺ–ł—Ź',
  '–°–Ķ–Ľ—Ć—Ā–ļ–ĺ–Ķ —Ö–ĺ–∑—Ź–Ļ—Ā—ā–≤–ĺ',
  '–Ē–ĺ–Ī—č—á–į –Ņ–ĺ–Ľ–Ķ–∑–Ĺ—č—Ö –ł—Ā–ļ–ĺ–Ņ–į–Ķ–ľ—č—Ö',
  '–Ę—Ä–į–Ĺ—Ā–Ņ–ĺ—Ä—ā –ł –Ľ–ĺ–≥–ł—Ā—ā–ł–ļ–į',
  '–ú–Ķ–ī–ł—Ü–ł–Ĺ—Ā–ļ–ł–Ķ —É—Ā–Ľ—É–≥–ł',
  '–ź—Ä—Ö–ł—ā–Ķ–ļ—ā—É—Ä–į –ł –Ņ—Ä–ĺ–Ķ–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ–ł–Ķ',
  '–ě–Ņ—ā–ĺ–≤–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź',
  '–†–Ķ–ļ–Ľ–į–ľ–Ĺ—č–Ķ —É—Ā–Ľ—É–≥–ł',
  '–†–į–∑—Ä–į–Ī–ĺ—ā–ļ–į –Ņ—Ä–ĺ–≥—Ä–į–ľ–ľ–Ĺ–ĺ–≥–ĺ –ĺ–Ī–Ķ—Ā–Ņ–Ķ—á–Ķ–Ĺ–ł—Ź',
  '–ģ—Ä–ł–ī–ł—á–Ķ—Ā–ļ–ł–Ķ —É—Ā–Ľ—É–≥–ł',
  '–ü—Ä–ĺ–ł–∑–≤–ĺ–ī—Ā—ā–≤–ĺ –ľ–Ķ–Ī–Ķ–Ľ–ł',
  '–§–ł–Ĺ–į–Ĺ—Ā–ĺ–≤—č–Ķ —É—Ā–Ľ—É–≥–ł',
  '–Ď—É—Ö–≥–į–Ľ—ā–Ķ—Ä—Ā–ļ–ł–Ļ —É—á—Ď—ā –ł –į—É–ī–ł—ā',
  '–†–Ķ—Ā—ā–ĺ—Ä–į–Ĺ–Ĺ—č–Ļ –Ī–ł–∑–Ĺ–Ķ—Ā',
];

function compactText(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeForMatch(s) {
  return compactText(s)
    .toLowerCase()
    .replace(/["¬ę¬Ľ']/g, '')
    .replace(/(^|[\s\-])(—ā–ĺ–ĺ|–į–ĺ|–ł–Ņ)(?=$|[\s\-])/giu, ' ')
    .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function detectCity(lower) {
  const cityRules = [
    { canon: '–ź—Ā—ā–į–Ĺ–į', regex: /(–Ĺ—É—Ä-?—Ā—É–Ľ—ā–į–Ĺ|–į—Ā—ā–į–Ĺ)/i },
    { canon: '–ź–Ľ–ľ–į—ā—č', regex: /(–į–Ľ–ľ–į—ā)/i },
    { canon: '–®—č–ľ–ļ–Ķ–Ĺ—ā', regex: /(—ą—č–ľ–ļ–Ķ–Ĺ—ā)/i },
    { canon: '–ö–į—Ä–į–≥–į–Ĺ–ī–į', regex: /(–ļ–į—Ä–į–≥–į–Ĺ–ī)/i },
    { canon: '–ź–ļ—ā–į—É', regex: /(–į–ļ—ā–į—É)/i },
    { canon: '–ź—ā—č—Ä–į—É', regex: /(–į—ā—č—Ä–į—É)/i },
    { canon: '–ü–į–≤–Ľ–ĺ–ī–į—Ä', regex: /(–Ņ–į–≤–Ľ–ĺ–ī–į—Ä)/i },
    { canon: '–ö–ĺ—Ā—ā–į–Ĺ–į–Ļ', regex: /(–ļ–ĺ—Ā—ā–į–Ĺ–į–Ļ)/i },
    { canon: '–£—Ā—ā—Ć-–ö–į–ľ–Ķ–Ĺ–ĺ–≥–ĺ—Ä—Ā–ļ', regex: /(—É—Ā—ā—Ć-?–ļ–į–ľ–Ķ–Ĺ–ĺ–≥–ĺ—Ä—Ā–ļ)/i },
  ];

  for (const rule of cityRules) {
    if (rule.regex.test(lower)) return rule.canon;
  }

  for (const [alias, canon] of Object.entries(cityAliases)) {
    if (lower.includes(alias)) return canon;
  }

  return null;
}

function detectActivity(lower) {
  for (const v of knownActivities) {
    if (lower.includes(v.toLowerCase())) return v;
  }

  if (/(—Ä–į–∑—Ä–į–Ī–ĺ—ā–ļ|–Ņ—Ä–ĺ–≥—Ä–į–ľ–ľ|it|–į–Ļ—ā–ł|software|—ā–Ķ—Ö–Ĺ–ĺ–Ľ–ĺ–≥)/i.test(lower)) return '–†–į–∑—Ä–į–Ī–ĺ—ā–ļ–į –Ņ—Ä–ĺ–≥—Ä–į–ľ–ľ–Ĺ–ĺ–≥–ĺ –ĺ–Ī–Ķ—Ā–Ņ–Ķ—á–Ķ–Ĺ–ł—Ź';
  if (/(—Ā—ā—Ä–ĺ–ł—ā|construction|–∑–ī–į–Ĺ–ł–Ļ|—Ā–ĺ–ĺ—Ä—É–∂–Ķ–Ĺ–ł–Ļ)/i.test(lower)) return '–°—ā—Ä–ĺ–ł—ā–Ķ–Ľ—Ć—Ā—ā–≤–ĺ –∑–ī–į–Ĺ–ł–Ļ –ł —Ā–ĺ–ĺ—Ä—É–∂–Ķ–Ĺ–ł–Ļ';
  if (/(—ā–Ķ—Ö–Ĺ–ł—á|–ĺ–Ī—Ā–Ľ—É–∂–ł–≤–į–Ĺ.*–ĺ–Ī–ĺ—Ä—É–ī)/i.test(lower)) return '–Ę–Ķ—Ö–Ĺ–ł—á–Ķ—Ā–ļ–ĺ–Ķ –ĺ–Ī—Ā–Ľ—É–∂–ł–≤–į–Ĺ–ł–Ķ –ĺ–Ī–ĺ—Ä—É–ī–ĺ–≤–į–Ĺ–ł—Ź';
  if (/(–į—Ä—Ö–ł—ā–Ķ–ļ—ā|–Ņ—Ä–ĺ–Ķ–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ)/i.test(lower)) return '–ź—Ä—Ö–ł—ā–Ķ–ļ—ā—É—Ä–į –ł –Ņ—Ä–ĺ–Ķ–ļ—ā–ł—Ä–ĺ–≤–į–Ĺ–ł–Ķ';
  if (/(—ā—Ä–į–Ĺ—Ā–Ņ–ĺ—Ä—ā|–Ľ–ĺ–≥–ł—Ā—ā|–ī–ĺ—Ā—ā–į–≤–ļ|—Ā–ļ–Ľ–į–ī)/i.test(lower)) return '–Ę—Ä–į–Ĺ—Ā–Ņ–ĺ—Ä—ā –ł –Ľ–ĺ–≥–ł—Ā—ā–ł–ļ–į';
  if (/(–ĺ–Ņ—ā–ĺ–≤)/i.test(lower)) return '–ě–Ņ—ā–ĺ–≤–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź';
  if (/(—Ä–ĺ–∑–Ĺ–ł—á)/i.test(lower)) return '–†–ĺ–∑–Ĺ–ł—á–Ĺ–į—Ź —ā–ĺ—Ä–≥–ĺ–≤–Ľ—Ź';
  if (/(—Ą–ł–Ĺ–į–Ĺ—Ā|–Ī–į–Ĺ–ļ|–ł–Ĺ–≤–Ķ—Ā—ā|—Ā—ā—Ä–į—Ö)/i.test(lower)) return '–§–ł–Ĺ–į–Ĺ—Ā–ĺ–≤—č–Ķ —É—Ā–Ľ—É–≥–ł';

  return null;
}

function normalizeLegalFormPrefix(s) {
  return compactText(s)
    .replace(/^—ā–ĺ–ĺ\b/i, '–Ę–ě–ě')
    .replace(/^–į–ĺ\b/i, '–ź–ě')
    .replace(/^–ł–Ņ\b/i, '–ė–ü');
}

function cleanupFreeformCompanyHint(raw, city) {
  let hint = normalizeForMatch(raw);
  if (!hint) return '';

  const cityNorm = normalizeForMatch(city || '');
  if (cityNorm) {
    const cityTokens = new Set(cityNorm.split(' ').filter(Boolean));
    hint = hint
      .split(' ')
      .filter((t) => t && !cityTokens.has(t))
      .join(' ');
  }

  hint = hint
    .replace(/\b(–ļ–į–ļ–ĺ–Ļ|–ļ–į–ļ–į—Ź|–ļ–į–ļ–ł–Ķ|–ļ–į–ļ—É—é|–≥–ī–Ķ|–ļ–ĺ–≥–ī–į|—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ|–ļ–ĺ–Ľ–ł—á–Ķ—Ā—ā–≤–ĺ|—á–ł—Ā–Ľ–ĺ|—Ā—ā–į—ā—É—Ā|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—Ź|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł–ł|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—é|–ī–į—ā–į|—Ä–Ķ–≥–ł—Ā—ā—Ä–į—Ü–ł–ł|–≤–ł–ī|–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā–ł|—á–Ķ–ľ|–∑–į–Ĺ–ł–ľ–į–Ķ—ā—Ā—Ź|–∑–į–Ĺ–ł–ľ–į—é—ā—Ā—Ź|–Ĺ–į–Ļ–ī–ł|–Ņ–ĺ–ļ–į–∂–ł|–Ņ–Ķ—Ä–Ķ—á–ł—Ā–Ľ–ł|—Ā–Ņ–ł—Ā–ĺ–ļ|–≤—Ā–Ķ|–Ņ–ĺ–ī–Ī–Ķ—Ä–ł|–Ņ–ĺ|–≤|—É|–Ĺ–į|–ł–∑)\b/giu, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return hint;
}

function detectLegalForm(chatInput) {
  const m = chatInput.match(/(?:^|[\s"¬ę¬Ľ'().,!?;:])(—ā–ĺ–ĺ|–į–ĺ|–ł–Ņ)(?=$|[\s"¬ę¬Ľ'().,!?;:])/iu);
  if (!m || !m[1]) return null;
  const v = m[1].toUpperCase();
  if (v === '–Ę–ě–ě' || v === '–ź–ě' || v === '–ė–ü') return v;
  return null;
}

function detectCompanyName(chatInput, lower, city) {
  const quotedLegal = chatInput.match(/(?:–Ę–ě–ě|–ź–ě|–ė–ü)\s*["¬ę][^"¬Ľ]+["¬Ľ]/i);
  if (quotedLegal && quotedLegal[0]) {
    const exact = normalizeLegalFormPrefix(quotedLegal[0].replace(/[¬ę¬Ľ]/g, '"'));
    const hint = normalizeForMatch(exact);
    return { exact, hint, confidence: 'high' };
  }

  const quotedAny = chatInput.match(/["¬ę]([^"¬Ľ]{2,})["¬Ľ]/);
  if (quotedAny && quotedAny[1]) {
    const exact = compactText(quotedAny[1]);
    const hint = normalizeForMatch(exact);
    return { exact: null, hint, confidence: 'medium' };
  }

  const phrase = chatInput.match(/(?:–ļ–ĺ–ľ–Ņ–į–Ĺ–ł[–ł—Ź–ł]\s+|—É\s+–ļ–ĺ–ľ–Ņ–į–Ĺ–ł[–ł—Ź–ł]\s+)([\p{L}\p{N}\s-]{3,})/iu);
  if (phrase && phrase[1]) {
    const raw = compactText(phrase[1]).replace(/[?!.,;:]+$/g, '');
    const hint = normalizeForMatch(raw);
    if (hint) return { exact: null, hint, confidence: 'low' };
  }

  const statusSubject = chatInput.match(/(?:–ļ–į–ļ–ĺ–Ļ\s+—Ā—ā–į—ā—É—Ā\s+—É|—Ā—ā–į—ā—É—Ā\s+—É)\s+([\p{L}\p{N}\s"¬ę¬Ľ.-]{3,})/iu);
  if (statusSubject && statusSubject[1]) {
    const raw = compactText(statusSubject[1])
      .replace(/[?!.,;:]+$/g, '')
      .replace(/\s+(–≤|–ł–∑|–Ņ–ĺ)\s+[^\s]+.*$/iu, '')
      .trim();
    const hint = normalizeForMatch(raw);
    if (hint && !/^(–ļ–ĺ–ľ–Ņ–į–Ĺ–ł|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—Ź|–ļ–ĺ–ľ–Ņ–į–Ĺ–ł—é)$/.test(hint)) {
      return { exact: null, hint, confidence: 'medium' };
    }
  }

  const freeformHint = cleanupFreeformCompanyHint(chatInput, city);
  if (freeformHint && freeformHint.split(' ').length <= 4) {
    return { exact: null, hint: freeformHint, confidence: 'low' };
  }

  return { exact: null, hint: null, confidence: 'none' };
}

function needsSemanticFallback(lower, hasAnyFilter, queryMode) {
  if (queryMode === 'generic') return true;
  if (!hasAnyFilter && queryMode === 'list') return true;
  if (/(–Ņ–ĺ—Ö–ĺ–∂|–į–Ĺ–į–Ľ–ĺ–≥|—Ā—Ö–ĺ–∂|–Ņ—Ä–ł–ľ–Ķ—Ä–Ĺ–ĺ|—ā–Ķ—Ö–Ĺ–ĺ–Ľ–ĺ–≥–ł—á–Ķ—Ā–ļ|—á—ā–ĺ[- ]?—ā–ĺ|–ļ–į–ļ–ł–Ķ\s+–Ķ—Ā—ā—Ć)/i.test(lower)) return true;
  return false;
}

function extractAnswerBranch(rawInput) {
  let text = compactText(rawInput);
  let branch = 'fast';

  const slashMode = text.match(/^\/mode\s+(rag|fast)\b/i);
  if (slashMode) {
    branch = slashMode[1].toLowerCase();
    text = compactText(text.replace(/^\/mode\s+(rag|fast)\b/i, ''));
    return { branch, chatInput: text };
  }

  const slashShort = text.match(/^\/(rag|fast)\b/i);
  if (slashShort) {
    branch = slashShort[1].toLowerCase();
    text = compactText(text.replace(/^\/(rag|fast)\b/i, ''));
    return { branch, chatInput: text };
  }

  const hashTag = text.match(/#(rag|fast)\b/i);
  if (hashTag) {
    branch = hashTag[1].toLowerCase();
    text = compactText(text.replace(/#(rag|fast)\b/i, ''));
  }

  return { branch, chatInput: text };
}

const getGlobalStaticData = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (typeof this !== 'undefined' && this && typeof this.getWorkflowStaticData === 'function') {
    return this.getWorkflowStaticData('global');
  }
  return null;
};

return $input.all().map((item) => {
  const original = item.json || {};
  const branchDecision = extractAnswerBranch(original.chatInput ?? '');
  const answerBranch = branchDecision.branch === 'rag' ? 'rag' : 'fast';
  const chatInput = compactText(branchDecision.chatInput || original.chatInput || '');
  const lower = chatInput.toLowerCase();

  const city = detectCity(lower);
  const activity = detectActivity(lower);
  const company = detectCompanyName(chatInput, lower, city);
  const legalForm = detectLegalForm(chatInput);

  const binMatch = chatInput.match(/\b\d{12}\b/);
  const bin = binMatch ? binMatch[0] : null;

  let status = null;
  if (/(–Ĺ–Ķ–į–ļ—ā–ł–≤|–Ľ–ł–ļ–≤–ł–ī|–∑–į–ļ—Ä—č—ā|–Ņ—Ä–ł–ĺ—Ā—ā–į–Ĺ–ĺ–≤)/i.test(lower)) status = '–õ–ł–ļ–≤–ł–ī–ł—Ä–ĺ–≤–į–Ĺ–ĺ';
  else if (lower.includes('–į–ļ—ā–ł–≤–Ĺ')) status = '–ź–ļ—ā–ł–≤–Ĺ–ĺ';

  const isCount = /(—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ|–ļ–ĺ–Ľ–ł—á–Ķ—Ā—ā–≤–ĺ|—á–ł—Ā–Ľ–ĺ)/i.test(lower);
  const isStatusLookup = /(–ļ–į–ļ–ĺ–Ļ\s+—Ā—ā–į—ā—É—Ā|—Ā—ā–į—ā—É—Ā\s+—É\s+–ļ–ĺ–ľ–Ņ–į–Ĺ–ł)/i.test(lower);
  const isDateLookup = /(–ī–į—ā–į\s+—Ä–Ķ–≥–ł—Ā—ā—Ä–į—Ü|–ļ–ĺ–≥–ī–į\s+–∑–į—Ä–Ķ–≥–ł—Ā—ā—Ä)/i.test(lower);
  const isActivityLookup = /(–≤–ł–ī\s+–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā|—á–Ķ–ľ\s+–∑–į–Ĺ–ł–ľ–į(?:–Ķ—ā—Ā—Ź|—é—ā|–Ķ—ą—Ć—Ā—Ź)|–ļ–į–ļ–į—Ź\s+–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā|–ļ–į–ļ–ĺ–Ļ\s+–≤–ł–ī\s+–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā|—á—ā–ĺ\s+–ī–Ķ–Ľ–į(?:–Ķ—ā|—é—ā)\s+–ļ–ĺ–ľ–Ņ–į–Ĺ–ł)/i.test(lower);
  const isList = /(–Ĺ–į–Ļ–ī–ł|–Ņ–ĺ–ļ–į–∂–ł|–Ņ–Ķ—Ä–Ķ—á–ł—Ā–Ľ–ł|–ļ–į–ļ–ł–Ķ|—Ā–Ņ–ł—Ā–ĺ–ļ|–≤—Ā–Ķ|–Ņ–ĺ–ī–Ī–Ķ—Ä–ł)/i.test(lower);

  const asksUnsupportedField = /(–≤—č—Ä—É—á–ļ|–ī–ĺ—Ö–ĺ–ī|–ĺ–Ī–ĺ—Ä–ĺ—ā|–Ņ—Ä–ł–Ī—č–Ľ|–ľ–į—Ä–∂–ł–Ĺ|ebitda|–ī–ł–≤–ł–ī–Ķ–Ĺ–ī|–ļ–į–Ņ–ł—ā–į–Ľ–ł–∑–į—Ü|–į–ļ—ā–ł–≤—č|–Ī–į–Ľ–į–Ĺ—Ā|—ā–Ķ–Ľ–Ķ—Ą–ĺ–Ĺ|e-?mail|–Ņ–ĺ—á—ā|—Ā–į–Ļ—ā|–į–ī—Ä–Ķ—Ā|—Ä—É–ļ–ĺ–≤–ĺ–ī–ł—ā–Ķ–Ľ|—É—á—Ä–Ķ–ī–ł—ā–Ķ–Ľ|–ī–ł—Ä–Ķ–ļ—ā–ĺ—Ä|–≤–Ľ–į–ī–Ķ–Ľ–Ķ—Ü|—ą—ā–į—ā|—Ā–ĺ—ā—Ä—É–ī–Ĺ–ł–ļ)/i.test(lower);
  const asksRankingWithoutMetric = /(–ļ—Ä—É–Ņ–Ĺ–Ķ–Ļ—ą|—ā–ĺ–Ņ\s*\d+|–Ľ—É—á—ą(–ł–Ļ|–į—Ź|–ł–Ķ)|—Ā–į–ľ(—č–Ļ|–į—Ź|–ĺ–Ķ|—č–Ķ))/i.test(lower);

  let unsupportedReason = null;
  if (asksUnsupportedField) unsupportedReason = '–ó–į–Ņ—Ä–ĺ—ą–Ķ–Ĺ—č –Ņ–ĺ–Ľ—Ź, –ļ–ĺ—ā–ĺ—Ä—č—Ö –Ĺ–Ķ—ā –≤ –ł—Ā—ā–ĺ—á–Ĺ–ł–ļ–Ķ –ī–į–Ĺ–Ĺ—č—Ö.';
  else if (asksRankingWithoutMetric) unsupportedReason = '–ó–į–Ņ—Ä–ĺ—ą–Ķ–Ĺ —Ä–Ķ–Ļ—ā–ł–Ĺ–≥/—Ā—Ä–į–≤–Ĺ–Ķ–Ĺ–ł–Ķ, –Ĺ–ĺ –≤ –ł—Ā—ā–ĺ—á–Ĺ–ł–ļ–Ķ –Ĺ–Ķ—ā –ľ–Ķ—ā—Ä–ł–ļ —Ä–į–Ĺ–∂–ł—Ä–ĺ–≤–į–Ĺ–ł—Ź.';

  let queryMode = 'generic';
  if (unsupportedReason) queryMode = 'unsupported';
  else if (isCount) queryMode = 'count';
  else if (bin) queryMode = 'bin_lookup';
  else if (isStatusLookup) queryMode = 'status_lookup';
  else if (isDateLookup) queryMode = 'registration_date_lookup';
  else if (isActivityLookup) queryMode = 'activity_lookup';
  else if (isList) queryMode = 'list';

  const shortEntityLookup =
    queryMode === 'generic'
    && !unsupportedReason
    && !bin
    && Boolean(company.hint)
    && !/(—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ|–ļ–ĺ–Ľ–ł—á–Ķ—Ā—ā–≤–ĺ|—á–ł—Ā–Ľ–ĺ|–Ĺ–į–Ļ–ī–ł|–Ņ–ĺ–ļ–į–∂–ł|–Ņ–Ķ—Ä–Ķ—á–ł—Ā–Ľ–ł|–ļ–į–ļ–ł–Ķ|—Ā–Ņ–ł—Ā–ĺ–ļ|–≤—Ā–Ķ|–Ņ–ĺ–ī–Ī–Ķ—Ä–ł|–Ņ–ĺ—Ö–ĺ–∂|–į–Ĺ–į–Ľ–ĺ–≥|—Ā—Ö–ĺ–∂|—ā–ĺ–Ņ|–ļ—Ä—É–Ņ–Ĺ–Ķ–Ļ—ą)/i.test(lower)
    && (Boolean(city) || Boolean(legalForm) || company.confidence === 'high' || company.hint.split(' ').length <= 3);

  if (shortEntityLookup) queryMode = 'status_lookup';

  const companyHintModes = new Set(['status_lookup', 'registration_date_lookup', 'activity_lookup', 'bin_lookup']);
  const companyHint = companyHintModes.has(queryMode) ? company.hint : null;

  const must = [];
  if (bin) must.push({ key: 'metadata.bin', match: { value: bin } });
  if (company.exact) must.push({ key: 'metadata.name', match: { value: company.exact } });
  if (city) must.push({ key: 'metadata.city', match: { value: city } });
  if (status) must.push({ key: 'metadata.status', match: { value: status } });
  if (activity) must.push({ key: 'metadata.activity', match: { value: activity } });

  const qdrantFilter = must.length ? { must } : {};
  const hasAnyFilter = must.length > 0;

  let retrievalMode = 'semantic';
  if (queryMode === 'unsupported') retrievalMode = 'none';
  else if (answerBranch === 'rag') retrievalMode = 'semantic';
  else if (!needsSemanticFallback(lower, hasAnyFilter, queryMode)) retrievalMode = 'metadata';

  const semanticTopK = queryMode === 'bin_lookup' ? 3 : 10;
  let metadataTopK = queryMode === 'count' ? 3000 : (queryMode === 'list' ? 100 : 25);
  if (companyHint && !company.exact) metadataTopK = Math.max(metadataTopK, 3000);

  const normalizedQuery = normalizeForMatch(chatInput);
  const CACHE_SCHEMA_VERSION = 'v8';
  const cacheKey = `${CACHE_SCHEMA_VERSION}:${answerBranch}:${normalizedQuery || lower}`;

  let cacheHit = false;
  let cachedResponseText = null;
  try {
    const s = getGlobalStaticData();
    if (s) {
      s.answerCache = s.answerCache || {};
      if (s.answerCache[cacheKey]) {
        cacheHit = true;
        cachedResponseText = s.answerCache[cacheKey];
      }
    }
  } catch (e) {
    // Optional cache: no-op if static data API is unavailable in current runtime.
  }

  const filterParts = [];
  if (bin) filterParts.push(`–Ī–ł–Ĺ=${bin}`);
  if (company.exact) filterParts.push(`–Ĺ–į–∑–≤–į–Ĺ–ł–Ķ=${company.exact}`);
  if (legalForm) filterParts.push(`—é—Ä—Ą–ĺ—Ä–ľ–į=${legalForm}`);
  if (city) filterParts.push(`–≥–ĺ—Ä–ĺ–ī=${city}`);
  if (status) filterParts.push(`—Ā—ā–į—ā—É—Ā=${status}`);
  if (activity) filterParts.push(`–≤–ł–ī_–ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā–ł=${activity}`);

  const retrievalHint = [
    `query_mode=${queryMode}`,
    `retrieval_mode=${retrievalMode}`,
    unsupportedReason ? `unsupported_reason=${unsupportedReason}` : '',
    '–ė—Ā–Ņ–ĺ–Ľ—Ć–∑—É–Ļ —ā–ĺ–Ľ—Ć–ļ–ĺ —Ą–į–ļ—ā—č –ł–∑ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–į.',
    '–ē—Ā–Ľ–ł –Ņ–ĺ–ī—Ö–ĺ–ī—Ź—Č–ł—Ö –∑–į–Ņ–ł—Ā–Ķ–Ļ –Ĺ–Ķ—ā, –≤–Ķ—Ä–Ĺ–ł –Ĺ–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö.',
  ].filter(Boolean).join('\n');

  const retrievalQuery = [
    retrievalHint,
    chatInput,
    filterParts.length ? `–§–ł–Ľ—Ć—ā—Ä—č: ${filterParts.join(', ')}` : '',
  ].filter(Boolean).join('\n');

  return {
    json: {
      ...original,
      chatInput,
      answerBranch,
      queryMode,
      retrievalMode,
      unsupportedReason,
      semanticTopK,
      metadataTopK,
      cacheKey,
      cacheHit,
      cachedResponseText,
      parsedFilters: {
        bin,
        companyName: company.exact,
        companyHint,
        companyConfidence: company.confidence,
        legalForm,
        city,
        status,
        activity,
      },
      qdrantFilter,
      retrievalQuery,
    },
  };
});

const items = $input.all();

function compact(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function normalizeForMatch(s) {
  return compact(s)
    .toLowerCase()
    .replace(/["¬ę¬Ľ']/g, '')
    .replace(/(^|[\s\-])(—ā–ĺ–ĺ|–į–ĺ|–ł–Ņ)(?=$|[\s\-])/giu, ' ')
    .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function pickQueryItem(allItems) {
  return allItems.find((i) => {
    const j = i?.json || {};
    return Boolean(j.queryMode || j.qdrantFilter || j.parsedFilters || j.retrievalMode || j.cacheKey);
  }) || { json: {} };
}

function toRecordFromDocument(doc) {
  const m = doc?.metadata || {};
  const rec = {
    bin: compact(m.bin),
    name: compact(m.name),
    city: compact(m.city),
    status: compact(m.status),
    activity: compact(m.activity),
    registration_date: compact(m.registration_date),
  };
  if (!/^\d{12}$/.test(rec.bin)) return null;
  return rec;
}

function getLegalForm(name) {
  const m = compact(name).match(/^(–Ę–ě–ě|–ź–ě|–ė–ü)(?=$|[\s"¬ę¬Ľ'().,!?;:])/iu);
  if (!m || !m[1]) return null;
  return m[1].toUpperCase();
}

const queryItem = pickQueryItem(items);
const query = queryItem.json || {};
const filters = (query.parsedFilters && typeof query.parsedFilters === 'object') ? query.parsedFilters : {};
const queryMode = compact(query.queryMode || 'generic');
const unsupportedReason = compact(query.unsupportedReason || '');

function isRagOutputItem(i) {
  const j = i?.json || {};
  if (j.document) return false;
  if (typeof j.text === 'string') return true;
  if (typeof j?.response?.text === 'string') return true;
  if (typeof j.response === 'string') return true;
  return false;
}

const answerBranchRaw = compact(query.answerBranch || '').toLowerCase();
const hasRagLikeOutput = items.some(isRagOutputItem);
const answerBranch = answerBranchRaw || (hasRagLikeOutput ? 'rag' : 'fast');
const modeLabel = answerBranch === 'rag' ? '[MODE: RAG]' : '[MODE: FAST]';

function withMode(text) {
  const body = String(text ?? '').trim();
  if (!body) return modeLabel;
  if (/^\[MODE:\s*(FAST|RAG)\]/i.test(body)) return body;
  return `${modeLabel}\n${body}`;
}

function extractJsonCandidate(s) {
  const text = compact(s);
  if (!text) return null;

  try {
    return JSON.parse(text);
  } catch (_) {}

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced && fenced[1]) {
    try {
      return JSON.parse(fenced[1].trim());
    } catch (_) {}
  }
  return null;
}

function extractAnswerFromRawText(s) {
  const text = compact(s);
  if (!text) return '';
  const m = text.match(/"answer"\s*:\s*"((?:\\.|[^"\\])*)"/i);
  if (!m || !m[1]) return '';
  try {
    return JSON.parse(`"${m[1]}"`);
  } catch (_) {
    return m[1].replace(/\\"/g, '"');
  }
}

function formatRagResponseText(raw) {
  const txt = compact(raw);
  if (!txt) return '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';

  const parsed = extractJsonCandidate(txt);
  if (!parsed || typeof parsed !== 'object') {
    const fallbackAnswer = compact(extractAnswerFromRawText(txt));
    if (fallbackAnswer && !/\\$/.test(fallbackAnswer)) return fallbackAnswer;
    return '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';
  }

  const answer = compact(parsed.answer || parsed.text || '');
  const evidence = Array.isArray(parsed.evidence) ? parsed.evidence.map((e) => compact(e)).filter(Boolean) : [];
  const itemsList = Array.isArray(parsed.items) ? parsed.items : [];

  let out = answer || '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';
  if (evidence.length) {
    out += '\n\n–ü–ĺ–ī—ā–≤–Ķ—Ä–∂–ī–Ķ–Ĺ–ł–Ķ:\n' + evidence.slice(0, 5).map((e) => `- ${e}`).join('\n');
  } else if (itemsList.length) {
    const lines = itemsList.slice(0, 5).map((it) => {
      const name = compact(it?.name);
      const bin = compact(it?.bin);
      const city = compact(it?.city);
      const status = compact(it?.status);
      return `- –Ě–į–∑–≤–į–Ĺ–ł–Ķ: ${name} | –Ď–ė–Ě: ${bin} | –ď–ĺ—Ä–ĺ–ī: ${city} | –°—ā–į—ā—É—Ā: ${status}`;
    }).filter(Boolean);
    if (lines.length) out += '\n\n–ü–ĺ–ī—ā–≤–Ķ—Ä–∂–ī–Ķ–Ĺ–ł–Ķ:\n' + lines.join('\n');
  }
  return out;
}

if (queryMode === 'unsupported' || unsupportedReason) {
  return [{ json: { response: { text: withMode('–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ. –Ē–ĺ—Ā—ā—É–Ņ–Ĺ—č —ā–ĺ–Ľ—Ć–ļ–ĺ –Ņ–ĺ–Ľ—Ź: –Ď–ė–Ě, –Ĺ–į–∑–≤–į–Ĺ–ł–Ķ, –≥–ĺ—Ä–ĺ–ī, —Ā—ā–į—ā—É—Ā, –≤–ł–ī –ī–Ķ—Ź—ā–Ķ–Ľ—Ć–Ĺ–ĺ—Ā—ā–ł, –ī–į—ā–į —Ä–Ķ–≥–ł—Ā—ā—Ä–į—Ü–ł–ł.') } } }];
}

if (query.cacheHit && query.cachedResponseText) {
  return [{ json: { response: { text: withMode(String(query.cachedResponseText)) } } }];
}

const ragItem = items.find(isRagOutputItem);
if (ragItem) {
  const ragRaw = ragItem?.json?.text || ragItem?.json?.response?.text || ragItem?.json?.response || '';
  const ragText = formatRagResponseText(ragRaw);
  return [{ json: { response: { text: withMode(ragText) } } }];
}

const docs = items
  .filter((i) => i?.json?.document)
  .map((i) => i.json.document)
  .filter(Boolean);

let records = docs.map(toRecordFromDocument).filter(Boolean);

const byBin = new Map();
for (const r of records) if (!byBin.has(r.bin)) byBin.set(r.bin, r);
records = [...byBin.values()];

function matchesStrictFilters(r) {
  if (filters.bin && r.bin !== String(filters.bin)) return false;
  if (filters.companyName && r.name !== String(filters.companyName)) return false;
  if (filters.legalForm && getLegalForm(r.name) !== String(filters.legalForm)) return false;
  if (filters.city && r.city !== String(filters.city)) return false;
  if (filters.status && r.status !== String(filters.status)) return false;
  if (filters.activity && r.activity !== String(filters.activity)) return false;
  return true;
}

function scoreByCompanyHint(r) {
  const hint = normalizeForMatch(filters.companyHint || '');
  if (!hint) return 0;
  const n = normalizeForMatch(r.name);
  if (!n) return 0;
  if (n === hint) return 100;
  if (n.includes(hint)) return 80;
  if (hint.includes(n)) return 60;
  const hintTokens = new Set(hint.split(' ').filter(Boolean));
  const nameTokens = n.split(' ').filter(Boolean);
  if (!hintTokens.size || !nameTokens.length) return 0;
  let inter = 0;
  for (const t of hintTokens) {
    if (nameTokens.includes(t)) {
      inter += 1;
      continue;
    }
    const partial = nameTokens.some((nt) => {
      if (nt.length < 4 || t.length < 4) return false;
      return nt.startsWith(t) || t.startsWith(nt);
    });
    if (partial) inter += 0.7;
  }
  return Math.round((inter / hintTokens.size) * 50);
}

const getGlobalStaticData = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (typeof this !== 'undefined' && this && typeof this.getWorkflowStaticData === 'function') {
    return this.getWorkflowStaticData('global');
  }
  return null;
};

let filtered = records.filter(matchesStrictFilters);

if (filters.companyHint) {
  const fuzzyMatched = filtered
    .map((r) => ({ r, s: scoreByCompanyHint(r) }))
    .filter((x) => x.s >= 30)
    .sort((a, b) => b.s - a.s)
    .map((x) => x.r);

  if (fuzzyMatched.length) filtered = fuzzyMatched;
  else if (!filters.companyName) filtered = [];
}

if (!filtered.length) {
  return [{ json: { response: { text: withMode('–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.') } } }];
}

const needsSingleRecord = ['status_lookup', 'registration_date_lookup', 'activity_lookup'].includes(queryMode);
if (needsSingleRecord && !filters.bin && !filters.companyName && filtered.length > 1) {
  const askParts = [];
  if (!filters.city) askParts.push('–≥–ĺ—Ä–ĺ–ī');
  if (!filters.legalForm) askParts.push('—é—Ä—Ą–ĺ—Ä–ľ—É (–Ę–ě–ě/–ź–ě/–ė–ü)');
  if (!askParts.length) askParts.push('–Ď–ė–Ě');

  const variants = filtered
    .slice(0, 5)
    .map((r) => `- ${r.name} ‚ÄĒ –≥–ĺ—Ä–ĺ–ī: ${r.city || '–Ĺ–Ķ —É–ļ–į–∑–į–Ĺ'}, –Ď–ė–Ě: ${r.bin}`);

  const clarifyText = [
    '–Ě–į–Ļ–ī–Ķ–Ĺ–ĺ –Ĺ–Ķ—Ā–ļ–ĺ–Ľ—Ć–ļ–ĺ –ļ–ĺ–ľ–Ņ–į–Ĺ–ł–Ļ —Ā –Ņ–ĺ—Ö–ĺ–∂–ł–ľ –Ĺ–į–∑–≤–į–Ĺ–ł–Ķ–ľ.',
    `–£—ā–ĺ—á–Ĺ–ł—ā–Ķ ${askParts.join(' –ł–Ľ–ł ')}.`,
    '–í–į—Ä–ł–į–Ĺ—ā—č:',
    ...variants,
  ].join('\n');

  return [{ json: { response: { text: withMode(clarifyText) } } }];
}

let answer = '';
if (queryMode === 'count') {
  const counted = Number(query.metadataCount || filtered.length || 0);
  answer = String(counted);
} else if (queryMode === 'status_lookup') {
  answer = filtered[0].status || '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';
} else if (queryMode === 'registration_date_lookup') {
  answer = filtered[0].registration_date || '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';
} else if (queryMode === 'activity_lookup') {
  answer = filtered[0].activity || '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';
} else if (queryMode === 'bin_lookup') {
  const r = filtered[0];
  answer = `${r.name}, ${r.city}, ${r.status}`;
} else {
  const names = [...new Set(filtered.map((r) => r.name).filter(Boolean))].slice(0, 5);
  answer = names.length ? names.join(', ') : '–Ě–Ķ–ī–ĺ—Ā—ā–į—ā–ĺ—á–Ĺ–ĺ –ī–į–Ĺ–Ĺ—č—Ö –≤ –ļ–ĺ–Ĺ—ā–Ķ–ļ—Ā—ā–Ķ.';
}

const evidenceLines = filtered.slice(0, 3).map((r) => `–Ě–į–∑–≤–į–Ĺ–ł–Ķ: ${r.name} | –Ď–ė–Ě: ${r.bin} | –ď–ĺ—Ä–ĺ–ī: ${r.city} | –°—ā–į—ā—É—Ā: ${r.status}`);

let finalText = answer;
if (evidenceLines.length) {
  finalText += '\n\n–ü–ĺ–ī—ā–≤–Ķ—Ä–∂–ī–Ķ–Ĺ–ł–Ķ:\n' + evidenceLines.map((x) => `- ${x}`).join('\n');
}
finalText = withMode(finalText);

try {
  if (query.cacheKey) {
    const s = getGlobalStaticData();
    if (!s) throw new Error('no_static_data_api');
    s.answerCache = s.answerCache || {};
    s.answerCache[query.cacheKey] = finalText;
  }
} catch (e) {
  // Optional cache write: no-op if static data API is unavailable in current runtime.
}

return [{ json: { response: { text: finalText } } }];

const inputItems = $input.all();

function asArray(v) {
  return Array.isArray(v) ? v : [];
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

const httpRequest = this.helpers.httpRequest.bind(this.helpers);

async function postJson(baseUrl, path, body, timeoutMs = 2500) {
  try {
    return await httpRequest({
      method: 'POST',
      url: `${baseUrl}${path}`,
      body: body || {},
      json: true,
      timeout: timeoutMs,
      headers: { 'Content-Type': 'application/json' },
    });
  } catch (err) {
    const status = err?.statusCode || err?.response?.statusCode || err?.response?.status || 'ERR';
    const msg = err?.message || err?.description || 'request_failed';
    throw new Error(`HTTP ${status} ${path}: ${msg}`);
  }
}

async function postWithFallback(baseUrls, path, body, timeoutMs = 2500) {
  let lastErr = null;
  for (const baseUrl of baseUrls) {
    try {
      return await postJson(baseUrl, path, body, timeoutMs);
    } catch (err) {
      lastErr = err;
      await sleep(20);
    }
  }
  throw lastErr || new Error(`Request failed: ${path}`);
}

function toDocItemFromPayload(payload) {
  const metadata = payload?.metadata || {};
  const pageContent = payload?.pageContent || '';
  return {
    json: {
      document: {
        pageContent,
        metadata,
      },
    },
  };
}

async function run() {
  const output = [];

  for (const item of inputItems) {
    const query = item?.json || {};

    if (query.queryMode === 'unsupported' || query.retrievalMode === 'none' || query.cacheHit) {
      output.push({ json: { ...query } });
      continue;
    }

    const qdrantUrls = ['http://qdrant:6333', 'http://localhost:6333'];
    const ollamaUrls = ['http://ollama:11434', 'http://localhost:11434'];

    const filter = query.qdrantFilter || {};
    const hasFilter = Boolean(filter && Array.isArray(filter.must) && filter.must.length);

    if (query.retrievalMode === 'metadata') {
      const countBody = {
        exact: true,
        ...(hasFilter ? { filter } : {}),
      };

      const countRes = await postWithFallback(qdrantUrls, '/collections/kz_companies/points/count', countBody, 3000);

      const scrollBody = {
        limit: Number(query.metadataTopK || 50),
        with_payload: true,
        with_vector: false,
        ...(hasFilter ? { filter } : {}),
      };

      const scrollRes = await postWithFallback(qdrantUrls, '/collections/kz_companies/points/scroll', scrollBody, 4000);
      const points = asArray(scrollRes?.result?.points);

      output.push({ json: { ...query, metadataCount: Number(countRes?.result?.count || 0) } });
      for (const p of points) {
        output.push(toDocItemFromPayload(p?.payload || {}));
      }
      continue;
    }

    const embBody = {
      model: 'bge-m3:latest',
      prompt: query.retrievalQuery || query.chatInput || '',
    };
    const embRes = await postWithFallback(ollamaUrls, '/api/embeddings', embBody, 4000);
    const embedding = embRes?.embedding;
    if (!Array.isArray(embedding) || !embedding.length) {
      output.push({ json: { ...query, retrievalError: 'embedding_failed' } });
      continue;
    }

    const searchBody = {
      vector: embedding,
      limit: Number(query.semanticTopK || 10),
      with_payload: true,
      with_vector: false,
      ...(hasFilter ? { filter } : {}),
    };
    const searchRes = await postWithFallback(qdrantUrls, '/collections/kz_companies/points/search', searchBody, 4500);
    const hits = asArray(searchRes?.result);

    output.push({ json: { ...query } });
    for (const h of hits) {
      output.push(toDocItemFromPayload(h?.payload || {}));
    }
  }

  return output;
}

return run();
